MaterialApp(
  onGenerateRoute: (settings) {
    switch (settings.name) {
      case '/':
        return MaterialPageRoute(builder: (context) => HomeScreen());
      case '/profile':
        return MaterialPageRoute(builder: (context) => ProfileScreen());
      case '/user':
        return MaterialPageRoute(builder: (context) => ProfileScreen());
      case '/product':
        if (settings.arguments is Map && (settings.arguments as Map).containsKey('id')) {
          return MaterialPageRoute(
            builder: (context) => ProductDetailScreen(id: (settings.arguments as Map)['id']),
          );
        }
        throw ArgumentError('Arguments invalides pour /product');
      default:
        return MaterialPageRoute(builder: (context) => NotFoundScreen());
    }
  },
);
```

